CREATE FUNCTION update_timestamp()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER set_timestamp
BEFORE UPDATE ON terms
FOR EACH ROW EXECUTE FUNCTION update_timestamp();

CREATE FUNCTION search_terms(query TEXT)
RETURNS SETOF terms AS $$
BEGIN
  RETURN QUERY
  SELECT * FROM terms
  WHERE label ILIKE '%' || query || '%'
  OR definition ILIKE '%' || query || '%';
END;
$$ LANGUAGE plpgsql;

